svg.script:
const WORLD_SIZE = 24.0;
const MAP_SIZE = 720.0;
const HALF = WORLD_SIZE / 2.0;
const SCALE = MAP_SIZE / WORLD_SIZE;
const SPAWN_RADIUS_M = 2.0;

let objects = [
  {kind:"crater", name:"c01", x:-8.5, y:6.5, r:2.1},
  {kind:"crater", name:"c02", x:-4.8, y:7.8, r:1.6},
  {kind:"crater", name:"c03", x:1.2, y:8.0, r:2.5},
  {kind:"crater", name:"c04", x:6.8, y:6.6, r:1.9},
  {kind:"crater", name:"c05", x:-9.0, y:1.6, r:1.8},
  {kind:"crater", name:"c06", x:-5.2, y:2.0, r:2.8},
  {kind:"crater", name:"c07", x:-0.6, y:3.0, r:1.4},
  {kind:"crater", name:"c08", x:4.2, y:2.4, r:2.2},
  {kind:"crater", name:"c09", x:8.2, y:1.5, r:1.5},
  {kind:"crater", name:"c10", x:-7.2, y:-2.8, r:2.4},
  {kind:"crater", name:"c11", x:-2.4, y:-1.6, r:1.7},
  {kind:"crater", name:"c12", x:2.2, y:-2.2, r:2.9},
  {kind:"crater", name:"c13", x:7.2, y:-3.0, r:2.1},
  {kind:"crater", name:"c14", x:-9.2, y:-7.0, r:1.5},
  {kind:"crater", name:"c15", x:-5.0, y:-7.2, r:2.2},
  {kind:"crater", name:"c16", x:-0.4, y:-6.2, r:1.8},
  {kind:"crater", name:"c17", x:4.4, y:-7.4, r:2.5},
  {kind:"crater", name:"c18", x:9.0, y:-7.0, r:1.4},
  {kind:"crater", name:"c19", x:0.0, y:0.0, r:1.2},
  {kind:"crater", name:"c20", x:9.2, y:8.8, r:1.2},
  {kind:"small_rock", name:"s01", x:-8.8, y:4.0},
  {kind:"small_rock", name:"s02", x:-6.0, y:5.2},
  {kind:"small_rock", name:"s03", x:-1.6, y:6.5},
  {kind:"small_rock", name:"s04", x:3.4, y:6.2},
  {kind:"small_rock", name:"s05", x:7.8, y:4.1},
  {kind:"small_rock", name:"s06", x:-8.0, y:-0.6},
  {kind:"small_rock", name:"s07", x:-3.7, y:-4.2},
  {kind:"small_rock", name:"s08", x:1.6, y:-5.1},
  {kind:"small_rock", name:"s09", x:5.8, y:-5.0},
  {kind:"small_rock", name:"s10", x:8.6, y:-1.2},
  {kind:"large_boulder", name:"b01", x:-6.8, y:0.8},
  {kind:"large_boulder", name:"b02", x:-1.2, y:1.4},
  {kind:"large_boulder", name:"b03", x:5.4, y:0.4},
  {kind:"large_boulder", name:"b04", x:-2.8, y:-7.8},
  {kind:"large_boulder", name:"b05", x:6.8, y:-7.2}
];

let selected = null;
let dragging = null;
let dragOffset = {x:0, y:0};

function mToPxX(x) { return (x + HALF) * SCALE; }
function mToPxY(y) { return (HALF - y) * SCALE; }
function pxToMX(px) { return px / SCALE - HALF; }
function pxToMY(py) { return HALF - py / SCALE; }
function clamp(v, lo, hi) { return Math.max(lo, Math.min(hi, v)); }

function drawGrid() {
  const grid = document.getElementById("gridLayer");
  grid.innerHTML = "";
  for (let m=-12; m<=12; m+=1) {
    let x = mToPxX(m);
    let y = mToPxY(m);
    let vl = document.createElementNS("http://www.w3.org/2000/svg", "line");
    vl.setAttribute("class", "grid");
    vl.setAttribute("x1", x); vl.setAttribute("x2", x);
    vl.setAttribute("y1", 0); vl.setAttribute("y2", MAP_SIZE);
    grid.appendChild(vl);
    let hl = document.createElementNS("http://www.w3.org/2000/svg", "line");
    hl.setAttribute("class", "grid");
    hl.setAttribute("x1", 0); hl.setAttribute("x2", MAP_SIZE);
    hl.setAttribute("y1", y); hl.setAttribute("y2", y);
    grid.appendChild(hl);
  }
  document.getElementById("xAxis").setAttribute("x1", 0);
  document.getElementById("xAxis").setAttribute("x2", MAP_SIZE);
  document.getElementById("xAxis").setAttribute("y1", mToPxY(0));
  document.getElementById("xAxis").setAttribute("y2", mToPxY(0));
  document.getElementById("yAxis").setAttribute("x1", mToPxX(0));
  document.getElementById("yAxis").setAttribute("x2", mToPxX(0));
  document.getElementById("yAxis").setAttribute("y1", 0);
  document.getElementById("yAxis").setAttribute("y2", MAP_SIZE);

  const sp = document.getElementById("spawnZone");
  sp.setAttribute("cx", mToPxX(0));
  sp.setAttribute("cy", mToPxY(0));
  sp.setAttribute("r", SPAWN_RADIUS_M * SCALE);
}

function render() {
  drawGrid();
  const layer = document.getElementById("objects");
  layer.innerHTML = "";
  for (const o of objects) {
    let el;
    if (o.kind === "crater") {
      el = document.createElementNS("http://www.w3.org/2000/svg", "circle");
      el.setAttribute("class", "crater" + (selected === o ? " selected" : ""));
      el.setAttribute("cx", mToPxX(o.x));
      el.setAttribute("cy", mToPxY(o.y));
      el.setAttribute("r", o.r * SCALE);
    } else {
      el = document.createElementNS("http://www.w3.org/2000/svg", "circle");
      el.setAttribute("class", o.kind === "small_rock" ? "stoneSmall" : "stoneLarge");
      el.setAttribute("cx", mToPxX(o.x));
      el.setAttribute("cy", mToPxY(o.y));
      el.setAttribute("r", o.kind === "small_rock" ? 6 : 11);
    }
    el.dataset.name = o.name;
    el.addEventListener("mousedown", startDrag);
    el.addEventListener("click", (e) => { selected = o; updateSelected(); render(); e.stopPropagation(); });
    layer.appendChild(el);

    const txt = document.createElementNS("http://www.w3.org/2000/svg", "text");
    txt.setAttribute("class", "label");
    txt.setAttribute("x", mToPxX(o.x) + 5);
    txt.setAttribute("y", mToPxY(o.y) - 5);
    txt.textContent = o.name;
    layer.appendChild(txt);
  }
  updateSelected();
}

function updateSelected() {
  const el = document.getElementById("selectedInfo");
  if (!selected) {
    el.textContent = "none";
    return;
  }
  if (selected.kind === "crater") {
    el.textContent = `${selected.name} crater: x=${selected.x.toFixed(2)}, y=${selected.y.toFixed(2)}, r=${selected.r.toFixed(2)}`;
  } else {
    el.textContent = `${selected.name} ${selected.kind}: x=${selected.x.toFixed(2)}, y=${selected.y.toFixed(2)}`;
  }
}

function getObjectByName(name) { return objects.find(o => o.name === name); }

function startDrag(evt) {
  const o = getObjectByName(evt.target.dataset.name);
  selected = o;
  const p = getMouse(evt);
  dragging = o;
  dragOffset.x = o.x - pxToMX(p.x);
  dragOffset.y = o.y - pxToMY(p.y);
  evt.preventDefault();
  evt.stopPropagation();
}

function getMouse(evt) {
  const svg = document.querySelector("svg");
  const pt = svg.createSVGPoint();
  pt.x = evt.clientX; pt.y = evt.clientY;
  const inv = document.getElementById("mapLayer").getScreenCTM().inverse();
  return pt.matrixTransform(inv);
}

document.addEventListener("mousemove", (evt) => {
  if (!dragging) return;
  const p = getMouse(evt);
  dragging.x = clamp(pxToMX(p.x) + dragOffset.x, -HALF, HALF);
  dragging.y = clamp(pxToMY(p.y) + dragOffset.y, -HALF, HALF);
  render();
});

document.addEventListener("mouseup", () => { dragging = null; });

document.getElementById("worldRect").addEventListener("click", () => {
  selected = null; updateSelected(); render();
});

document.getElementById("mapLayer").addEventListener("wheel", (evt) => {
  if (selected && selected.kind === "crater") {
    const step = evt.deltaY < 0 ? 0.1 : -0.1;
    selected.r = clamp(selected.r + step, 0.3, 5.0);
    render();
    evt.preventDefault();
  }
});

function resizeSelected(delta) {
  if (selected && selected.kind === "crater") {
    selected.r = clamp(selected.r + delta, 0.3, 5.0);
    render();
  }
}

document.getElementById("smallerBtn").addEventListener("click", () => resizeSelected(-0.1));
document.getElementById("largerBtn").addEventListener("click", () => resizeSelected(0.1));
document.getElementById("exportBtn").addEventListener("click", exportTable);

document.addEventListener("keydown", (evt) => {
  if (!selected) return;
  if (evt.key === "+" || evt.key === "=") resizeSelected(0.1);
  if (evt.key === "-" || evt.key === "_") resizeSelected(-0.1);
});

function fmt(v) { return Number(v).toFixed(3); }

function exportTable() {
  let lines = ["kind,name,x_m,y_m,radius_m,asset,scale,yaw_deg"];
  for (const o of objects) {
    if (o.kind === "crater") {
      lines.push(["crater", o.name, fmt(o.x), fmt(o.y), fmt(o.r), "", "", ""].join(","));
    } else if (o.kind === "small_rock") {
      lines.push(["rock", o.name, fmt(o.x), fmt(o.y), "", "apollo_sample20", "18.0", "0"].join(","));
    } else if (o.kind === "large_boulder") {
      lines.push(["rock", o.name, fmt(o.x), fmt(o.y), "", "lunalab_boulder1", "1.0", "0"].join(","));
    }
  }
  document.getElementById("exportText").value = lines.join("\\n");
}

render();
exportTable();
